/* DbM Framework - Debug Toolbar JS */ (() => { const toolbar = document.getElementById('dbmToolbarRoot'); if (!toolbar) return; document.querySelectorAll('.dbm-toolbar-item[data-panel]').forEach(item => { item.addEventListener('click', () => { const panelId = item.dataset.panel; const panel = document.getElementById(panelId); if (!panel) return; document.querySelectorAll('.dbm-toolbar-panel').forEach(p => { if (p !== panel) p.classList.remove('active'); }); panel.classList.toggle('active'); }); }); document.getElementById('dbmClose')?.addEventListener('click', () => { toolbar.remove(); }); })();